function pastel(c: string, pct = 22): string {
    return c ? "color-mix(in srgb, " + c + " " + pct + "%, #ffffff)" : "#ffffff"
}
function initialTile(c: string): { bg: string; fg: string } {
    // 차분한 이니셜 (무작위 hue 폐기) — 공식색 있으면 파스텔+색 글자, 없으면 토스식 회청 단색
    if (c) return { bg: "color-mix(in srgb, " + c + " 24%, #ffffff)", fg: c }
    return { bg: "#e8ecf1", fg: "#5b6c80" }
}
function bfUrl(p: string, size: number): string {
    return p ? "https://cdn.brandfetch.io/" + p + "?c=" + BF_CID + "&w=" + size * 2 + "&h=" + size * 2 : ""
}
function Tile({ size, bg, src, pad, ch }: any) {
    const [err, setErr] = useState(false)
    const r = Math.round(size * 0.32)
    return (
        <span style={{ width: size, height: size, borderRadius: r, background: bg, display: "inline-flex", alignItems: "center", justifyContent: "center", overflow: "hidden", flexShrink: 0 }}>
            {src && !err ? (
                <img src={src} alt="" width={size} height={size} onError={() => setErr(true)}
                    style={{ width: size, height: size, objectFit: "contain", padding: pad, boxSizing: "border-box", display: "block", borderRadius: r }} />
            ) : (
                <span style={{ color: "#fff", fontSize: Math.round(size * 0.42), fontWeight: 800 }}>{ch}</span>
            )}
        </span>
    )
}

